	for i := 0; i < n; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			resp, err := http.Get(url)
			if err != nil {
				errors <- err
				return
			}
			defer resp.Body.Close()
			if resp.StatusCode == http.StatusOK {
				responses <- 1
			}
		}()
	}

	// Wait for all goroutines to complete
	wg.Wait()
	close(responses)
	close(errors)

	// Compile results
	for r := range responses {
		result.mu.Lock()
		result.successCount += r
		result.mu.Unlock()
	}

	for range errors {
		result.mu.Lock()
		result.errorCount++
		result.mu.Unlock()
	}

	return result
}

func main() {
	url := "http://example.com"
	n := 10

	// Run the goroutines and gather the result
	result := go(url, n)

	// Log the compiled results
	fmt.Printf("Total successful responses: %d\n", result.successCount)
	fmt.Printf("Total errors encountered: %d\n", result.errorCount)
}
